<span class="line">            permit<span class="token punctuation">.</span>api<span class="token punctuation">.</span>users<span class="token punctuation">.</span><span class="token function">sync</span><span class="token punctuation">(</span>user<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// Syncs the new user with the Permit service</span></span>
