<span class="line">            <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">UnauthorizedException</span><span class="token punctuation">(</span><span class="token string">&quot;Not logged in&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
